var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"도착했네. 이 앞이 재건 도시야.","JPN":"着いた。この先が再建都市だ。","ENG":"We're here. Just ahead is the Rebuilt City.","TWN":"到了，前面就是重建城市。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"태워줘서 고마워.","JPN":"乗せてくれたこと、感謝する。","ENG":"Thanks for the ride.","TWN":"謝謝你載我來。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"도시라는 이름에 비하면, 별로 번화해 보이진 않지만 말이지.","JPN":"都市という名のわりには、あまり賑わっているようには見えないな。","ENG":"Though for something called a city, it doesn't look that bustling.","TWN":"但這裡好像談不上是一座城市，沒有城市的繁華感。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"<color=#ffd34c>재건</color>도시니까요. 여긴 얼마 전까지만 해도 사람이 못 사는 폐허였어요.","JPN":"<color=#ffd34c>再建</color>都市ですからね。ちょっと前までは人が住めない廃墟でした。","ENG":"Well, it's been <color=#ffd34c>rebuilt</color>. This place was just ruins no one could live in until recently.","TWN":"因為是<color=#ffd34c>重建</color>城市。這裡在不久前都還是個無人居住的廢墟。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"관리국이 본격적으로 재건을 시작한 지는 아직 2개월 밖에 안 됐거든요.","JPN":"管理局が本格的に再建を始めて、まだ2か月しか経ってないんです。","ENG":"The Administration only started rebuilding here about two months ago.","TWN":"管理局正式開始重建也才兩個月。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신들, 고철을 아주 많이도 싣고 왔던데.","JPN":"お前たち、鉄くずをかなり多く積んでいたが。","ENG":"You guys brought a mountain of scrap metal with you.","TWN":"你們車上載了很多廢鐵。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"관리국에 무기 납품이라도 하는 건가?","JPN":"管理局に武器の納品でもしているのか？","ENG":"Supplying weapons to the Administration or something?","TWN":"是給管理局送武器嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이게 뭔지 궁금하다면 따라와도 상관없네. 바쁘지 않다면 말이야.","JPN":"気になるなら付いて来ても構わん。他に用事がなければだが。","ENG":"If you're curious, you're welcome to tag along. Assuming you're not busy.","TWN":"好奇的話可以一起來，如果你不忙的話。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"참.","JPN":"そうだ。","ENG":"Oh, right.","TWN":"對了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"아이들은 좋아하는 편인가?","JPN":"子どもは好きか？","ENG":"Do you like kids?","TWN":"你喜歡小孩嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"아이들?","JPN":"子ども？","ENG":"Kids?","TWN":"小孩？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"어, 사부님이다!","JPN":"わ、師匠だ！","ENG":"Hey, it's Mr. Seosaeng!","TWN":"哇，是老師！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L23_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"사부니임!! 가슴 큰 언니도 같이 왔네!","JPN":"師匠！！　胸のおっきなお姉さんもいっしょだ！","ENG":"Mr. Seosaeng! And you also brought your friend with big boobs too!","TWN":"老師！！胸部大的姊姊也來了！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L24_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"크, 흠! 그렇게 부르지 말래두.","JPN":"ご、ごほん！　そんな呼び方するんじゃないって。","ENG":"Ahem! I told you not to call me that.","TWN":"咳，咳！就叫你不要這樣叫我。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그래. 다들 평안히 지내셨나?","JPN":"ああ、皆元気にしていたか？","ENG":"Good to see you all doing well.","TWN":"大家過得還好嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"이것 보세요! 사부님이 전에 가르쳐주신대로 만들었어요!","JPN":"これ見てください！　前に教えてもらったとおり作りました！","ENG":"Look! I made this just like you taught me!","TWN":"老師你看！我照老師教的做出來囉！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L28_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"굴뚝 청소 토끼 1호랑 2호요!","JPN":"煙突掃除うさぎ1号と2号！","ENG":"It's chimney-sweeper rabbit #1 and #2!","TWN":"煙囪清潔兔1號和2號！"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"음… 내 안목이 틀리지 않았군.","JPN":"うむ……やはり某の目に狂いはなかったな。","ENG":"Hmm… Looks like I wasn't wrong about you.","TWN":"嗯…我的眼光沒錯。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"역시 두 사람에겐 소질이 있어. 작은 톱니 하나까지 흠결 없는 작품일세.","JPN":"2人には才能がある。小さな歯車の一つまで、非の打ち所のない作品だ。","ENG":"You really have a knack for this. Every gear is perfect.","TWN":"你們兩個人果然有天賦，連最小的齒輪都非常完美。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"에헤헤- 칭찬 받았다아-","JPN":"えへへ……ほめられた！","ENG":"Hehe! I got a compliment!","TWN":"嘿嘿嘿，被稱讚了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"다 사부님이 가르쳐주신 거잖아요.","JPN":"師匠のおかげです。","ENG":"It's all thanks to you.","TWN":"這都是老師教得好。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"나중엔 더 유용한 것도 만들어보고 싶어요. 사부님의 침식 경보 장치 같은 것처럼요.","JPN":"これからもっと役に立つものも作りたいです。師匠の侵食警報装置みたいな。","ENG":"Someday I want to make something really useful, like your Corruption alert device.","TWN":"我以後也想做出更有用的東西，像老師的侵蝕警報裝置一樣。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"좋은 마음가짐이야.","JPN":"よい心構えだ。","ENG":"That's a good goal.","TWN":"很棒的想法。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"더 나은 발전을 기대하는 의미로 선물을 준비해왔는데, 한 번 써보겠나?","JPN":"更なる発展を期待するという意味でプレゼントを持ってきたのだが、使ってみるか？","ENG":"In fact, I brought you a gift to help with that. Want to try it out?","TWN":"為了鼓勵你們更進一步，我準備了禮物，要不要用看看？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"선물이요-?","JPN":"プレゼント～？","ENG":"A gift?","TWN":"禮物嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"아하핫, 동월! 이것 봐! 내가 달리고 있어!","JPN":"あははっ、トウゲツ！　見て！　アタシ、走ってる！","ENG":"Haha! Dongwol, look! I'm running! On my own legs!","TWN":"哈哈哈，佟月！你看！我在跑欸！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L49_1","type":"dialog","speaker":"CHILD_NPC_GIRL_14","text":{"KOREA":"하나도 안 힘들어! 백 킬로도 안 쉬고 달릴 수 있을 것 같아!","JPN":"全然疲れないよ！　100kmだって一気に走れそう！","ENG":"It's so easy! I feel like I could run a hundred kilometers without stopping!","TWN":"而且一點都不累！感覺可以不休息地跑上一百公里！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L1_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"정말이야… 서연이가 휠체어 없이 두 다리로 뛰다니.","JPN":"本当だ……シュエンが車椅子なしに、二本脚で走ってる。","ENG":"Whoa! Seoyeon's really running on two legs!","TWN":"是真的欸！書妍用兩條腿在跑步。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"동월. 자네 것도 동기화가 끝났네. 한 번 움직여보겠나?","JPN":"トウゲツ、そなたのものも同期化が完了した。動かしてみるか？","ENG":"Dongwol, yours just finished syncing too. Give it a try.","TWN":"佟月，你的也同步好了，要不要試試看？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"앗, 네!","JPN":"あっ、はい！","ENG":"Ah, okay!","TWN":"好！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L8_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"내가 원하는 대로 움직여요. 손가락까지.","JPN":"指までボクの思い通りに動いてる……","ENG":"It moves exactly how I want. Even my fingers.","TWN":"它會跟著我的想法動，連手指也是。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"이거…! 정말로 제 팔 같아요! 감사합니다, 사부님!","JPN":"これ……！　本当に自分の腕みたいです！　ありがとうございます、師匠！","ENG":"They feel…! Just like my real arms! Thank you, Mr. Seosaeng!","TWN":"這個…！真的就像我的手臂一樣！謝謝老師！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"동월이는 좋겠네.","JPN":"よかったね、トウゲツ。","ENG":"Good for you, Dongwol.","TWN":"佟月很開心吧。"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"이제 만들고 싶은 것도 전보다 더 잘 만들 수 있겠다. 그치?","JPN":"これで作りたかったものももっと上手く作れるね！","ENG":"Now you'll be able to make even better things, right?","TWN":"這樣你以後做東西就更方便囉？"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHILD_NPC_BOY_14","text":{"KOREA":"…네! 얼른 해보고 싶어요!","JPN":"……はい！　早くやってみたいです！","ENG":"…Yeah! I want to get started right away!","TWN":"…對呀！真想趕快動手做做看！"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SKY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그 언니는 어디 갔어? 방금까지 있었는데.","JPN":"あのお姉さんは？　さっきまでいたのに。","ENG":"Where'd the one following us go? She was just here.","TWN":"那個姊姊人呢？剛才還在這裡的。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"사람을 찾고 있다지 않았나. 실마리라도 떠올린 모양이지.","JPN":"人を探していると言っていたのだ。何か手がかりでも思い出したのだろう。","ENG":"Didn't she say she was looking for someone? Maybe she remembered something.","TWN":"她說她來找人，看來是有線索了。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"전화 받았습니다.","JPN":"もしもし。","ENG":"Hello?","TWN":"喂，請說。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L27_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"이지수다.","JPN":"ムラサメ・シノだ。","ENG":"Lee Jisoo speaking.","TWN":"我是李智秀。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"모르는 번호로 전화를 걸 줄은 몰랐네요. 전용 통신기도 지급해드렸을 텐데요.","JPN":"知らない番号で電話をかけてくるとは思いませんでしたね。専用の通信機もお渡ししていたはずですが。","ENG":"Didn't expect you to call from an unknown number. We gave you a secure comms device.","TWN":"沒想到你會用陌生電話打來。我不是有給你專用的通訊器嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"망가졌어. 수리를 맡길 만한 데가 없더군.","JPN":"壊れた。修理を任せられそうなところがなくてな。","ENG":"It broke. And there's nowhere around here to get it fixed.","TWN":"壞了，附近沒地方可以修。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"기대한 것보다 연락이 늦었어요.","JPN":"期待していたより遅かったですね。","ENG":"Took you long enough to report in.","TWN":"我以為你會早點打來。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"타깃은 찾았습니까?","JPN":"ターゲットは見つかりましたか？","ENG":"Have you found the target?","TWN":"找到目標了嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"의심되는 인물은 찾았다.","JPN":"それらしい人物は見つけた。","ENG":"I found someone who might be.","TWN":"找到一個可疑人物。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"하지만 확실치 않아. 좀 더 지켜볼 시간이 필요해.","JPN":"ただ確証がない。しばらくは様子を見るつもりだが。","ENG":"But I need more time to be sure.","TWN":"但還不確定，需要更多時間觀察。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"그렇게 하세요.","JPN":"そうですか。","ENG":"Do what you must.","TWN":"可以。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"하지만 예정보다 너무 늦어지면, 다른 조가 그 임무를 대신하게 될 겁니다.","JPN":"ですが、予定より遅くなり過ぎるとその任務は他のチームが担当することになるでしょう。","ENG":"But if you take too long, another unit will be sent to finish the job.","TWN":"但如果拖太久，其他小組會代替你完成這個任務。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"내 임무에 참견할 셈인가?","JPN":"私の任務に口出しする気か？","ENG":"You're planning to meddle in my mission?","TWN":"你是要干涉我的任務嗎？"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"펠릭스님께서 당신에게 임무를 맡기긴 했지만, 이건 당신의 개인적인 문제가 아녜요.","JPN":"確かにフェリックス様はあなたに任務を任せましたが、これはあなた個人の問題ではありません。","ENG":"Felix may have given you this mission, but this isn't your personal vendetta.","TWN":"緋莉克絲雖然把任務交給你，但這不是你的私人問題。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"WATCHER_NPC_NULL_14","text":{"KOREA":"타깃을 제거하는 게 우리의 목표이니까요.","JPN":"ターゲットを排除することが、私たちの目標なんです。","ENG":"Our goal is to eliminate the target, one way or another.","TWN":"我們的目標是除掉目標人物。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"일이 마무리되면 이쪽에서 먼저 연락하지.","JPN":"事が済んだらこちらから連絡する。","ENG":"I'll reach out once it's done.","TWN":"事情辦完後我會主動聯絡你。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"통화 끝났어. 빌려줘서 고맙군.","JPN":"通話は終わった。貸してもらって感謝する。","ENG":"I'm done. Thanks for the phone.","TWN":"通話結束，謝謝你借我電話。"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"고맙긴요. 그럼…","JPN":"どういたしまして。では……","ENG":"Don't mention it. Well then…","TWN":"不客氣…"},"stage":{"bg":"NEWTOWN","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PERSON_EXTRA_NULL_MINWOO","text":{"KOREA":"어? 이게 왜 이러지? 갑자기 전원이 안 들어오잖아?","JPN":"あれ？　どうしたんだろ？　急に電源が入らない！？","ENG":"Huh? What's wrong with this thing? It just shut off.","TWN":"咦？怎麼回事？突然沒電了？"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…아마도 나 때문일 거다.","JPN":"……多分私のせいだ。","ENG":"…Probably my fault.","TWN":"…可能是我造成的。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"기기 값은 배상하지.","JPN":"端末の代金は弁償する。","ENG":"I'll pay you for the device.","TWN":"我會賠償你手機的錢。"},"stage":{"bg":"NEWTOWN","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"지금까지 한 얘길 정리해보죠.","JPN":"今までの話をまとめてみましょう。","ENG":"Let's sum this up.","TWN":"我們來整理一下你剛才說的話。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"언니가 남의 폰을 망가뜨려서 폰 값을 물어줘야 한다는 것까진 이해했어요.","JPN":"お姉さんが人の携帯電話を壊して、弁償せざるを得なくなったってことは分かりました。","ENG":"I understand that you broke some guy's phone and now you have to pay for it.","TWN":"你弄壞了別人的手機，所以要賠償手機錢，到這裡我還可以理解。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그런데 그게 언니가 우리 회사에 취업하는 거랑 무슨 상관인데요?","JPN":"でも、それがなんでお姉さんがうちの会社に就職することに繋がるんですか？","ENG":"But what does that have to do with you working at our company?","TWN":"但這跟你在我們公司上班有什麼關係？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"회사라면 안전요원 한 명쯤 필요하지 않나?","JPN":"会社ならボディーガードの一人くらい必要なんじゃないか？","ENG":"Doesn't your company need at least one security guard?","TWN":"公司不是需要一個保鑣嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"당신들은 침식지대를 들락거리며 자주 위험에 처하는 것 같던데, 날 고용하면 당신들의 안전을 책임져주겠단 뜻이야.","JPN":"お前たちは侵食地帯に頻繁に出入りして危機に晒されることも多いようだが、私を雇えば、身の安全が保証される。","ENG":"You seem to wander into dangerous Corrupted Areas a lot. If you hire me, I'll keep you safe.","TWN":"你們經常出入侵蝕地帶會遇到危險，請我的話可以保障你們的安全。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우리가 사람이 필요한 건 맞지만, 챙겨야 할 것이 비단 안전뿐만은 아니라네.","JPN":"我らが人手不足であることは確かだが、やってもらうことは身の安全を守ることだけではない。","ENG":"We do need people, yes, but safety isn't our only concern.","TWN":"我們確實需要人，但要顧及的不只是安全。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"다른 일도 시킬 셈인가?","JPN":"他の仕事もやらせる気か？","ENG":"Planning to dump other chores on me too?","TWN":"你還要我做別的事嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"뭐, 간단한 잡무 정도라면 조금 거들어줄 수도 있겠지.","JPN":"まあ、簡単な雑務ぐらいなら、少し手伝ってやることはできるだろう。","ENG":"Fine. I can help with basic errands.","TWN":"嗯，簡單的雜務我也可以做。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"쇠는 좀 다룰 줄 아나?","JPN":"鉄は扱えるか？","ENG":"Do you know how to work with metal?","TWN":"你會處理金屬嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"글쎄. 이 검으로 쇠를 벨 수는 있는데.","JPN":"さあ、この剣で鉄を斬ることはできるが。","ENG":"Not exactly. But I can cut it with this sword.","TWN":"可以吧，我能用這把劍斬斷金屬。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"합격…","JPN":"合格だ……","ENG":"You're hired…","TWN":"錄用…"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"잠… 사부?! 그렇게 쉽게 결정해도 돼?","JPN":"まっ……師匠！？　そんな簡単に決めていいの？","ENG":"Hold up… Master?! You're hiring her just like that?","TWN":"等一下…師父？！這麼隨便就決定沒問題嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"검으로 쇠를 자르는 기술자는 흔치 않으니까.","JPN":"剣で鉄が斬れる技術者は珍しい。","ENG":"Not many technicians can cut metal with a sword.","TWN":"能用劍斬斷金屬的技術人員可不多。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"그걸 기술자라고 부르는 게 맞아?!","JPN":"それ技術者って言っていいの？","ENG":"You think she's a technician?!","TWN":"這能叫技術人員嗎？！"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이 계약서를 작성하기 전에. 우리에겐 함께 일하며 지켜야 할 <color=#ffd34c>세 가지 수칙</color>이 있네.","JPN":"この契約書を作成する前に、我らには共に働く上で守ってもらわねばならない<color=#ffd34c>3つのルール</color>がある。","ENG":"Before you sign, there are <color=#ffd34c>three rules</color> you'll have to follow while working with us.","TWN":"在簽這份合約之前。我們有一條必須遵守的<color=#ffd34c>三條規定</color>。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이 수칙을 따르지 않겠다면 고용 건은 철회하지.","JPN":"このルールに従わないなら、雇用の件は撤回しよう。","ENG":"If you can't accept them, the deal's off.","TWN":"如果你不遵守這三條規定，我就會解雇你。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"세 가지 수칙? 우리 공방에 그런 게 있었나?","JPN":"3つのルール？　うちの工房にそんなのあったっけ？","ENG":"Three rules? Since when did we have those?","TWN":"三條規定？我們有這種規定嗎？"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…말해봐.","JPN":"……聞こう。","ENG":"…Speak.","TWN":"…說吧。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"첫째, 반찬 투정은 금물일세.","JPN":"その1、食事の好き嫌いは禁物だ。","ENG":"First, no complaining about food.","TWN":"第一，不能挑食。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우린 매 끼니에 쌀밥을 먹는다네. 계란찜을 포함해서 말이지.","JPN":"我らは毎日白米を食べる。茶碗蒸しを含めてな。","ENG":"We eat rice every meal. And that includes steamed eggs.","TWN":"我們每餐都吃白米飯，還有蒸蛋。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"문제없어. 나도 저 애 요리는 입맛에 맞았거든.","JPN":"問題ない。私もあの子の料理は口に合ったから。","ENG":"No problem. The kid's cooking suited my taste.","TWN":"沒問題，我也覺得她的手藝很合我的胃口。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"둘째, 재능이 없다고 쉽게 포기하지 말 것.","JPN":"その2、才能がないからと簡単に諦めないこと。","ENG":"Second, don't give up just because you think you lack talent.","TWN":"第二，不要覺得沒有天賦就輕易放棄。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"검 휘두르는 것 말고 배워야 할 게 있다면, 노력 정도는 해보지.","JPN":"剣を振る以外にも習うべきことがあるなら、努力はしてみることだ。","ENG":"If there's something to learn besides swinging a sword, I'll at least give it a try.","TWN":"除了揮劍之外，如果還有什麼要學的，我會努力試試。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"뭐야, 사부. 무게는 잔뜩 잡더니 별 얘기도 아니네.","JPN":"なーんだ、師匠。深刻な話かと思ったら、大したことないじゃん。","ENG":"Seriously, Master? Why did you make it sound so dramatic?","TWN":"師父，你這樣很像一臉正經地說幹話。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ANDY_ATELIER_NULL_NULL","text":{"KOREA":"저기. 두 사람 면접 대충 끝나면 차로 올래? 난 장 본 거 싣고 있을 테니까.","JPN":"ね、2人とも面接が終わったら車に来てくれる？　私は買い物したやつ乗せてるから。","ENG":"Anyway, when you two are done playing job interview, meet me at the truck. I'll load the groceries.","TWN":"那個，你們面試結束後，可以到車上來嗎？我要去裝採買的東西。"},"stage":{"bg":"BACKSTREET","bgm":"THEMA_SOF_JOHN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDY_ATELIER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그대 말처럼, 우린 종종 목숨이 걸린 위기를 맞닥뜨리곤 하지.","JPN":"そなたの言う通り、我らは時折命に関わる危機に瀕することがある。","ENG":"Like you said, we do face life-or-death risks now and then.","TWN":"正如你所說，我們經常遇到生命危險的情況。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"만에 하나, 회사의 안전요원으로서 모두를 구할 수 없을 때가 온다면…","JPN":"万が一、この会社のボディーガードとして、全員を救うことは無理と判断した場合……","ENG":"If there ever comes a time you can't save everyone as our guard…","TWN":"萬一，當你身為公司的保鑣，卻無法顧及所有人時…"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND_DAY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나보다는 저 아이를 먼저 구하게.","JPN":"某よりはあの子を優先して助けたまえ。","ENG":"Save that kid first. Not me.","TWN":"先救她。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그게 세 번째 수칙인가?","JPN":"それが3つ目のルールか？","ENG":"That's the third rule?","TWN":"這是第三條規定嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이해 안 되는 점 있나?","JPN":"理解できなかった点はあるか？","ENG":"Anything unclear?","TWN":"有什麼不懂的地方嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"의도는 이해했어. 확인 차 물어봤을 뿐이야.","JPN":"意図は理解した。確認する意味で聞いただけだ。","ENG":"Understood. Just wanted to be sure.","TWN":"懂是懂，只是確認一下。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그러고 보니…","JPN":"そういえば……","ENG":"By the way…","TWN":"那…"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"회사 이름이 뭐지?","JPN":"会社の名前は何だ？","ENG":"What's your company called?","TWN":"公司叫什麼名字？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"노스텔지어.","JPN":"ノスタルジア。","ENG":"Nostalgia.","TWN":"追舊。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"회사가 아니라 연구소라네. 사업보단 연구를 하는 곳이지.","JPN":"会社ではなく研究所だ。ビジネスというより、研究を行っている。","ENG":"It's not really a company but a research lab. We focus more on studies than business.","TWN":"我們不是間公司，是研究室。主要做研究，而不是賺錢。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"연구소?","JPN":"研究所？","ENG":"A research lab?","TWN":"研究室？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"돈을 안 벌면 밑천은 어디서 마련하지? 당신 부자였어?","JPN":"収益がないなら資金はどこから調達している？　お前、金持ちなのか？","ENG":"So how do you fund it? You rich or something?","TWN":"不賺錢的話，資金從哪來？你是富豪嗎？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"달마다 개런티로 받는 돈이 있어. 전에 다니던 직장에서 내 처우를 제법 괜찮게 봐줬거든.","JPN":"毎月手当として幾分かもらっている。前の職場でかなりいい待遇をしてもらってな。","ENG":"I get a stipend every month. My last company treated me pretty well when I left.","TWN":"每個月都會有一筆錢進來。我之前工作的公司給我的待遇還不錯。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"개런티로 회사를 운영하다니. 그 사람들에겐 당신이 은인쯤 되는 모양이네.","JPN":"経営ができるほどの手当か……その人たちにとって、お前は恩人か何かなのか？","ENG":"Running an entire lab with a stipend? You must be a hero to them.","TWN":"竟然靠工作待遇就可以經營一家公司，我看你是他們的救命恩人吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"나 또한 그 덕에 무소불위를 누리고 있으니, 서로가 서로의 은인인 셈이지.","JPN":"某もそのおかげで、気の赴くままにやっているわけであるから、お互いが恩人であろう。","ENG":"And I get to do whatever I want in return. So I'd say we're even.","TWN":"拜他們所賜，我才能做自己想做的事，所以我們算是彼此的恩人吧。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"솔직히 처음 다 무너져가는 당신네 건물을 봤을 땐, 직원 월급도 못 챙길 만큼 형편이 나쁜 줄 알았는데.","JPN":"正直、今にも崩れそうな建物を最初に見た時は、社員の給料もまともに払えないくらい状況が悪いのかと思ったが。","ENG":"Honestly, when I first saw your run-down base, I thought you couldn't even pay your staff.","TWN":"說實話，我第一次看到你們這棟破爛的建築物時，還以為你們窮到連員工薪水都付不起。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이 돈으로 깔끔한 건물을 한 채 지을 수도 있겠지만 큰 의미는 없을 걸세.","JPN":"その金で立派な建物を建てることもできるが、さして価値のあることとも思えん。","ENG":"I could build something better, sure. But what's the point?","TWN":"是可以蓋一棟乾淨的建築物，但意義不大。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"이곳 KS일대에 내리는 먹비는 무분별해 보여도 일종의 규칙성을 띄지. 그래서 우리 연구소도 그 규칙을 분석해 정기적으로 거취를 옮기고 있어.","JPN":"このKS一帯に降る墨雨は、一見無秩序に見えるがある規則性をもっている。ゆえに我らの研究所もその規則性を分析し、定期的に拠点を移動しているのだ。","ENG":"The Ink Rain in this KS region follows a pattern. We move our lab around to stay aligned with it.","TWN":"墨雨在 KS-7 這一帶，雖然看起來雜亂無章，但其實有某種規律。所以我們的研究室也會分析這個規律，定期搬家。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"먹비를 맞는 게 걱정이면 차라리 도시 같은 청정구역을 거점으로 삼는 게 낫지 않아?","JPN":"墨雨に降られるのが心配なら、侵食の恐れのない都市を拠点にしたほうがいいんじゃないか？","ENG":"If you're that worried about the Ink Rain, why not set it up somewhere safe in the city?","TWN":"如果擔心墨雨，不如把據點設在安全的城市裡吧？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우리가 연구 중인 먹비의 에너지는 휘발성이 강하다네. 그래서 흩어지기 전에 포집하고 그것을 이용하려면 되도록 현장과 가까운 편이 좋지.","JPN":"我らが研究している墨雨のエネルギーは揮発性が高い。蒸発してしまう前に捕集し利用するためには、なるべく現場に近い方が有利なのだ。","ENG":"The Ink Rain's energy we study dissipates fast. We have to be close to the scene to harvest it.","TWN":"我們正在研究的墨雨，其揮發性很強。因此必須在它消失前收集到，並利用它，所以盡量靠近現場比較好。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"위험하기 짝이 없는 연구 환경이군.","JPN":"危険極まりない研究環境だな。","ENG":"What a dangerous way to do research.","TWN":"真是個充滿危險的研究環境。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그런 고생을 자처하면서까지 뭘 찾고 있는 거야?","JPN":"そこまでして苦労を買って出て、何を探しているんだ？","ENG":"What are you trying to find that's worth all this?","TWN":"你這麼自討苦吃，到底在尋找什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"하나뿐이지만 두 번 다신 만질 수 없는 것.","JPN":"唯一でありながら、二度と触れられないもの。","ENG":"Something you only get once but can never touch again.","TWN":"一個獨一無二，卻再也無法觸及的東西。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"수수께끼는 별로 좋아하지 않는데.","JPN":"謎解きはあまり好きじゃないな。","ENG":"I don't like riddles.","TWN":"我不太喜歡猜謎。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"…지나간 과거일세.","JPN":"……過ぎ去った過去だ。","ENG":"…The past.","TWN":"…是逝去的過去。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"우린 과거로 가는 장치를 만들고 있어.","JPN":"我らは過去に行ける装置を作っている。","ENG":"We're building a machine to go back.","TWN":"我們正在製作回到過去的裝置。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"현실성이 있는 얘기인진 모르겠지만 열심히 해봐. 힘이 닿는 데까진 도와줄 테니.","JPN":"現実的かどうかはさておき、頑張ってみるんだな。できる限りのことは協力するから。","ENG":"Can't say I buy it, but good luck. I'll help however I can.","TWN":"我不知道你這樣是不是天馬行空，但你就加油吧。我會在力所能及的範圍內幫助你。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L46_1","type":"dialog","speaker":"SEOSAENG_ATELIER_NULL_BLADE","text":{"KOREA":"그러고 보니, 그대가 찾고 있다던 사람은 만났나?","JPN":"そういえば、探している人には会えたのか？","ENG":"By the way, did you ever find the person you were looking for?","TWN":"說到這個，你要找的人找到了嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_BLADE","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"글쎄. 어디로 도망갈 위인은 아닌 것 같거든.","JPN":"さあ、あちこち逃げ回るようなたちではないみたいだしな。","ENG":"Hard to say. Doesn't seem like the type to run.","TWN":"不確定，但應該不會跑掉吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그래서 시간 들여 천천히 찾아보려고.","JPN":"じっくり、時間をかけて探すつもりだ。","ENG":"So I'll just take my time and keep looking.","TWN":"所以我打算花點時間慢慢找。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};